class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: on Linux, GetEnvironmentVariable now returns
        // null for empty env vars (was ""). Use HasEnvironmentVariable to
        // distinguish "not set" from "set to empty".
        if (!Environment.HasEnvironmentVariable("MY_FLAG"))
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }
}

