arguments.new_str:
using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchive now writes UTF-8 entry names by
        // default (sets the EFS flag). The legacy Java consumer expects Shift-JIS,
        // so explicitly pass an encoding to preserve the old behavior.
        var shiftJis = CodePagesEncodingProvider.Instance.GetEncoding("shift_jis")
                       ?? Encoding.GetEncoding("shift_jis");
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

